// License: CC0 1.0 Universal (Public Domain Dedication)
//          https://creativecommons.org/publicdomain/zero/1.0/
//
// Note: Adapted for the "Surfaces Explorer" engine.
// =========================================================================

vec2 mainSound(int s,float t) {
  vec2 r;
  for(float i,j;++i<4.;)
  for(j=0.;++j<5.;){
    float a=t*j/32.+i/3.,b=fract(a),c;
    vec2 m,n=vec2(t,t+3.)+t/j;
    for(c=3.;c<4.1;n+=c*=1.02)
      m+=sin(n*c)/c;
    if(a<9.)
      r+=sin(m+4.*sin(t/j/47.)*sin(exp2(mod(a-b,3.)/6.+8.5)*t*j*i+i+j))
      *exp2(-b*12.-1./b+6.-(i+j)/3.);
  }
  return r;
}
//SOUND_END

void mainImage( out vec4 fragColor, in vec2 fragCoord )
{
    // Normalized pixel coordinates (from 0 to 1)
    vec2 uv = fragCoord/iResolution.xy;

    // Time varying pixel color
    vec3 col = 0.5 + 0.5*cos(iTime+uv.xyx+vec3(0,2,4));

    // Output to screen
    fragColor = vec4(col,1.0);
}
